type ToolStatus =
  | 'pending'
  | 'running'
  | 'awaiting-approval'
  | 'succeeded'
  | 'failed'
  | 'cancelled';

type ToolInvocationState<TInput = unknown, TOutput = unknown> = {
  id: string;
  name: string;
  status: ToolStatus;
  input?: TInput;
  output?: TOutput;
  error?: string;
  startedAt?: number;
  finishedAt?: number;
  requiresUserAction?: boolean;
};

